solution: class Solution {
public:
    long long smallestNumber(long long num) {
        if (num == 0) return 0;
        bool neg = num < 0;
        string s = to_string(abs(num));
        sort(s.begin(), s.end(), greater<char>());
        if (neg) {
            long long res = 0;
            for (char c : s) res = res * 10 + (c - '0');
            return -res;
        } else {
            int firstNonZero = 0;
            while (firstNonZero < s.size() && s[firstNonZero] == '0') ++firstNonZero;
            if (firstNonZero < s.size()) swap(s[0], s[firstNonZero]);
            sort(s.begin() + 1, s.end());
            long long res = 0;
            for (char c : s) res = res * 10 + (c - '0');
            return res;
        }
    }
};
efficiency: HIGH
time complexity: O(D log D) where D is the number of digits
space complexity: O(D)
energy implications: LOW
explanation: Convert the absolute value to a string, sort digits in descending order for negative numbers (to make the magnitude largest, hence the value smallest), and in ascending order for positive numbers after moving the first non-zero digit to the front to avoid leading zeros.

